mapper.insert:
insert into property_deals (
    deal_type, lawd_cd, umd_nm, house_name, house_type, jibun, road_name, build_year,
    exclusive_area, land_area, deal_year, deal_month, deal_day, deal_amount, deposit,
    monthly_rent, floor, deal_gbn, raw_xml
) values (
    #{dealType}, #{lawdCd}, #{umdNm}, #{houseName}, #{houseType}, #{jibun}, #{roadName}, #{buildYear},
    #{exclusiveArea}, #{landArea}, #{dealYear}, #{dealMonth}, #{dealDay}, #{dealAmount}, #{deposit},
    #{monthlyRent}, #{floor}, #{dealGbn}, #{rawXml}
)

mapper.select:
select count(*) from property_deals
where deal_type = #{dealType}
  and lawd_cd = #{lawdCd}
  and deal_year = cast(substring(#{dealYmd}, 1, 4) as int)
  and deal_month = cast(substring(#{dealYmd}, 5, 2) as int)
